// Recoger todos los eventos del día y extraer las horas ocupadas
const items = $input.all();
const FIXED_BLOCKS = ['08:00', '10:00', '14:00', '15:00'];
const occupied = [];

for (const item of items) {
  const ev = item.json;
  if (!ev.start) continue;

  const startStr = ev.start.dateTime || ev.start.date;
  if (!startStr) continue;

  const startDate = new Date(startStr);
  const endStr = ev.end?.dateTime || ev.end?.date;
  const endDate = endStr ? new Date(endStr) : new Date(startDate.getTime() + 60*60*1000);

  // Obtener la fecha base del query para construir bloques
  const queryDate = $node['Webhook (Disponibilidad)'].json.query.date; // YYYY-MM-DD

  for (const block of FIXED_BLOCKS) {
    const [bh, bm] = block.split(':').map(Number);
    // Construir bloque en hora Colombia (UTC-5)
    const blockStartStr = `${queryDate}T${block}:00-05:00`;
    const blockStart = new Date(blockStartStr);
    const blockEnd = new Date(blockStart.getTime() + 2 * 60 * 60 * 1000);

    // Solapamiento: eventStart < blockEnd AND eventEnd > blockStart
    if (startDate < blockEnd && endDate > blockStart) {
      if (!occupied.includes(block)) {
        occupied.push(block);
      }
    }
  }
}

return { occupied_slots: occupied };
